#include <stdio.h>
#include <string.h>
#include <stdbool.h>
#define MAXV (1<<20)
static bool isPrime[MAXV];
void sieve(){
    for(int i=2;i<MAXV;i++) isPrime[i]=true;
    for(int p=2;p*p<MAXV;p++) if(isPrime[p])
        for(int q=p*p;q<MAXV;q+=p) isPrime[q]=false;
}
int main(){
    sieve();
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[100005];
    while(T--){
        scanf("%s",s);
        int n=strlen(s);
        int ans=0;
        for(int i=0;i<n && !ans;i++) if(s[i]=='1'){
            int val=0;
            for(int len=1;len<=20 && i+len<=n;len++){
                val = (val<<1) + (s[i+len-1]-'0');
                if(isPrime[val]){ ans=1; break; }
            }
        }
        puts(ans?"Yes":"No");
    }
    return 0;
}

