import java.io.*;
import java.util.*;
public class Main {
    static final int LIM = 1<<20;
    static boolean[] isPrime = new boolean[LIM];
    static void sieve(){
        Arrays.fill(isPrime, true);
        isPrime[0]=isPrime[1]=false;
        for(int p=2;p*p<LIM;++p) if(isPrime[p])
            for(int q=p*p;q<LIM;q+=p) isPrime[q]=false;
    }
    public static void main(String[] args) throws Exception{
        FastScanner fs = new FastScanner(System.in);
        sieve();
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            String s = fs.next();
            int n = s.length();
            boolean ok = false;
            for(int i=0;i<n && !ok;i++) if(s.charAt(i)=='1'){
                int val = 0;
                for(int len=1; len<=20 && i+len<=n; ++len){
                    val = (val<<1) + (s.charAt(i+len-1)-'0');
                    if(isPrime[val]){ ok = true; break; }
                }
            }
            out.append(ok?"Yes":"No").append('\n');
        }
        System.out.print(out.toString());
    }
    // fast scanner
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1<<16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){ in = new BufferedInputStream(is); }
        private int readByte(){
            if(ptr>=len){
                try{ len = in.read(buffer); ptr = 0; }catch(IOException e){ return -1; }
                if(len<=0) return -1;
            }
            return buffer[ptr++];
        }
        String next(){
            StringBuilder sb = new StringBuilder();
            int c;
            while((c=readByte())!=-1 && c<=32);
            while(c!=-1 && c>32){ sb.append((char)c); c=readByte(); }
            return sb.toString();
        }
        int nextInt(){ return Integer.parseInt(next()); }
    }
}

