#!/usr/bin/env python3
import sys
MAXV = 1<<20
is_prime = [True]*MAXV
is_prime[0]=is_prime[1]=False
for p in range(2,int(MAXV**0.5)+1):
    if is_prime[p]:
        step = p
        start = p*p
        for q in range(start, MAXV, step):
            is_prime[q]=False

def solve():
    data = sys.stdin.read().strip().split()
    if not data: return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        s = data[idx]; idx+=1
        n = len(s)
        ok = False
        for i,ch in enumerate(s):
            if ch!='1':
                continue
            val = 0
            for l in range(1,21):
                if i+l>n: break
                val = (val<<1) + (ord(s[i+l-1]) - 48)
                if is_prime[val]:
                    ok = True
                    break
            if ok:
                break
        out.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

